import sys
import os
import grpc


class UCSecurableError(Exception):
    """Structured exception for UC securable gRPC client errors.

    Carries error class, subclass, and message parameters from the Failure proto
    so they can be propagated through the taco UDF server to become
    SparkRuntimeException with the correct error classification.
    """

    def __init__(self, error_class, subclass, message_parameters,
                 originating_in_payload, message, cause=None):
        super().__init__(message)
        self.error_class = error_class
        self.subclass = subclass
        self.message_parameters = message_parameters
        self.originating_in_payload = originating_in_payload
        self.__cause__ = cause


def _extract_failure_from_grpc_error(e):
    """Extract a Failure proto from a gRPC error's trailing metadata.

    Returns a dict with error_class, subclass, message_parameters,
    originating_in_payload, and message if found, or None.
    """
    try:
        # grpc.RpcError (when it's a grpc.Call) has trailing_metadata()
        if not hasattr(e, "trailing_metadata"):
            return None
        metadata = e.trailing_metadata()
        if metadata is None:
            return None

        # Look for grpc-status-details-bin in trailing metadata
        status_bytes = None
        for key, value in metadata:
            if key == "grpc-status-details-bin":
                status_bytes = value
                break

        if status_bytes is None:
            return None

        from google.rpc import status_pb2
        rpc_status = status_pb2.Status()
        rpc_status.ParseFromString(
            status_bytes if isinstance(status_bytes, bytes)
            else status_bytes.encode("latin-1"))

        if len(rpc_status.details) == 0:
            return None

        from databricks.failure_pb2 import Failure
        failure = Failure()
        if not rpc_status.details[0].Unpack(failure):
            return None
        if not failure.error_class:
            return None

        return {
            "error_class": failure.error_class,
            "subclass": failure.subclass,
            "message_parameters": dict(failure.message_parameters),
            "originating_in_payload": failure.originating_in_payload,
            "message": failure.message,
        }
    except Exception:
        return None


def handle_grpc_error(e):
    """Handle a gRPC error by extracting structured error info and raising UCSecurableError.

    If structured error info is found in the Failure proto, raises UCSecurableError.
    If the status is UNIMPLEMENTED, raises UCSecurableError with RPC_NOT_SUPPORTED.
    Otherwise, raises UCSecurableError with INTERNAL_UNKNOWN.
    """
    failure_info = _extract_failure_from_grpc_error(e)

    if failure_info is not None:
        raise UCSecurableError(
            error_class=failure_info["error_class"],
            subclass=failure_info["subclass"],
            message_parameters=failure_info["message_parameters"],
            originating_in_payload=failure_info["originating_in_payload"],
            message=failure_info["message"],
            cause=e,
        )

    # Check for UNIMPLEMENTED status
    if hasattr(e, "code") and callable(e.code):
        if e.code() == grpc.StatusCode.UNIMPLEMENTED:
            raise UCSecurableError(
                error_class="UNSUPPORTED_UDF_FEATURE",
                subclass="RPC_NOT_SUPPORTED",
                message_parameters={},
                originating_in_payload=True,
                message="The requested operation is not supported by the "
                        "current Databricks runtime version.",
                cause=e,
            )

    # Fallback: internal unknown error
    raise UCSecurableError(
        error_class="UDF_ERROR",
        subclass="INTERNAL_UNKNOWN",
        message_parameters={},
        originating_in_payload=False,
        message=f"Error in gRPC call: {e}",
        cause=e,
    )


class SingletonMeta(type):
    """Metaclass for enforcing the Singleton pattern."""

    _instances = {}

    def __call__(cls, *args, **kwargs):
        if cls not in cls._instances:
            cls._instances[cls] = super().__call__(*args, **kwargs)
        return cls._instances[cls]

    @classmethod
    def reset_instance(cls):
        """Resets all singleton instances (for testing purposes)."""
        cls._instances = {}


class BaseGrpcClient(metaclass=SingletonMeta):
    """Base class for gRPC service clients connecting via Unix domain socket."""

    # Env var names for the UC securable socket path.
    _SOCKET_PATH_ENV = "DB_UC_SECURABLE_SOCKET_PATH"
    _LEGACY_SOCKET_PATH_ENV = "SERVICE_CREDENTIAL_SOCKET_PATH"

    @staticmethod
    def get_socket_path():
        """Return the UC securable socket path from env vars, or None."""
        return (
            os.getenv(BaseGrpcClient._SOCKET_PATH_ENV)
            or os.getenv(BaseGrpcClient._LEGACY_SOCKET_PATH_ENV)
        )

    def __init__(self):
        self._socket_path = None
        self._channel = None
        self._sandbox_uuid = None

        socket_path = self.get_socket_path()
        if not socket_path:
            raise UCSecurableError(
                error_class="UDF_ERROR",
                subclass="INTERNAL_UNKNOWN",
                message_parameters={},
                originating_in_payload=False,
                message="UC securable socket path is not configured.",
            )

        if not os.path.exists(socket_path):
            raise UCSecurableError(
                error_class="UDF_ERROR",
                subclass="INTERNAL_UNKNOWN",
                message_parameters={},
                originating_in_payload=False,
                message=f"UC securable socket at {socket_path} does not exist.",
            )

        # Get the sandbox UUID for verification
        self._sandbox_uuid = (
            os.getenv("DB_SANDBOX_UUID") or os.getenv("SANDBOX_UUID")
        )

        # Set socket path before creating channel
        self._socket_path = socket_path
        self._channel = grpc.insecure_channel(f"unix:{self._socket_path}")

    @property
    def channel(self):
        """Returns the gRPC channel."""
        return self._channel

    @property
    def sandbox_uuid(self):
        """Returns the sandbox UUID."""
        return self._sandbox_uuid

    def reset(self):
        """Resets the client instance, allowing reinitialization."""
        try:
            # Close the channel
            self._channel.close()
        except Exception as e:
            # Channel might already be closed
            print(
                "Tried to close channel as part of reset, but failed with error.",
                e,
                file=sys.stderr,
            )
            pass
        SingletonMeta.reset_instance()
